mepc_setup:       
                  la x15, init
                  csrw 0x341, x15

custom_csr_setup: 
                  csrwi 0x7c0, 1

init_machine_mode:
                  li x15, 0x1f8018b2
                  csrw 0x300, x15 # MSTATUS
                  li x15, 0xd24edbfb
                  csrw 0x304, x15 # MIE
                  li x2, 0x8ffffffc
