                  slli x15, x15, 8
                  addi x15, x15, 0x0
                  sw x15, 0(x2)
                  csrr x15, 0x300
                  csrr x2, 0x304
                  csrw 0x300, x15
                  csrw 0x304, x2
                  j main
test_done:        
                  li x2, 0x8ffffff8
                  li x15, 0x0
                  slli x15, x15, 8
                  addi x15, x15, 0x1
                  sw x15, 0(x2)
                  ecall

